code.C++:
int findSingleNumber(const vector<int> &numbers) {
    int x = 0;
    for (int num : numbers) x ^= num;
    return x;
}

code.Python3:
def findSingleNumber(numbers):
    x = 0
    for n in numbers:
        x ^= n
    return x

code.C:
long long findSingleNumber(int* numbers, int size) {
    long long unique = 0;
    for (int i = 0; i < size; i++) {
        unique ^= (long long)numbers[i];
    }
    return unique;
}

code.Java:
static int findSingleNumber(int[] arr) {
    int xorr = 0;
    for (int x : arr) {
        xorr ^= x;
    }
    return xorr;
}

